import test from "node:test";
import assert from "node:assert/strict";

import { FragmentAssembler } from "../src/fragment-assembler.mjs";
import { readAuditExport } from "../src/audit-export-reader.mjs";

function encode(records) {
  return Buffer.from(records.map((record) => "\x1e" + JSON.stringify(record) + "\n").join(""), "utf8");
}

test("sequence namespaces are independent for interleaved channels", () => {
  const assembler = new FragmentAssembler();
  assert.equal(assembler.apply({ channel: "red", sequence: 0, text: "R0" }).kind, "applied");
  assert.equal(assembler.apply({ channel: "blue", sequence: 0, text: "B0" }).kind, "applied");
  assert.equal(assembler.apply({ channel: "red", sequence: 1, text: "R1" }).kind, "applied");
  assert.equal(assembler.apply({ channel: "blue", sequence: 1, text: "B1" }).kind, "applied");
  assert.deepEqual(assembler.snapshot(), { blue: "B0B1", red: "R0R1" });
});

test("reader retains every channel when their counters advance in parallel", async () => {
  const bytes = encode([
    { channel: "north", sequence: 0, text: "N0/" },
    { channel: "south", sequence: 0, text: "S0/" },
    { channel: "south", sequence: 1, text: "S1" },
    { channel: "north", sequence: 1, text: "N1" }
  ]);
  const cuts = [7, 31, 58, bytes.length];
  const chunks = [];
  let start = 0;
  for (const end of cuts) {
    chunks.push(bytes.subarray(start, end));
    start = end;
  }

  const result = await readAuditExport(chunks);
  assert.deepEqual(result, { north: "N0/N1", south: "S0/S1" });
});
